## iOS Development (Swift/SwiftUI)

### SwiftUI Modern Patterns

```swift
import SwiftUI
import Combine

@MainActor
class UserViewModel: ObservableObject {
    @Published var users: [User] = []
    @Published var isLoading = false
    @Published var error: Error?

    private var cancellables = Set<AnyCancellable>()
    private let service: UserService

    init(service: UserService = .shared) {
        self.service = service
    }

    func loadUsers() async {
        isLoading = true
        defer { isLoading = false }

        do {
            users = try await service.fetchUsers()
        } catch {
            self.error = error
        }
    }
}

struct UserListView: View {
    @StateObject private var viewModel = UserViewModel()
    @Environment(\.colorScheme) var colorScheme

    var body: some View {
        NavigationStack {
            List(viewModel.users) { user in
                NavigationLink(value: user) {
                    UserRow(user: user)
                }
            }
            .navigationTitle("Users")
            .navigationDestination(for: User.self) { user in
                UserDetailView(user: user)
            }
            .refreshable {
                await viewModel.loadUsers()
            }
            .overlay {
                if viewModel.isLoading {
                    ProgressView()
                }
            }
        }
        .task {
            await viewModel.loadUsers()
        }
    }
}
```

### iOS Architecture Patterns

- **MVVM-C**: Model-View-ViewModel with Coordinators
- **TCA**: The Composable Architecture
- **VIPER**: View-Interactor-Presenter-Entity-Router
- **Clean Architecture**: Domain-driven design

## Android Development (Kotlin/Jetpack Compose)

### Jetpack Compose Modern UI

```kotlin
@Composable
fun UserListScreen(
    viewModel: UserViewModel = hiltViewModel(),
    onNavigateToDetail: (User) -> Unit
) {
    val uiState by viewModel.uiState.collectAsStateWithLifecycle()

    LazyColumn(
        modifier = Modifier.fillMaxSize(),
        contentPadding = PaddingValues(16.dp),
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        when (uiState) {
            is UiState.Loading -> {
                item {
                    Box(
                        modifier = Modifier.fillMaxWidth(),
                        contentAlignment = Alignment.Center
                    ) {
                        CircularProgressIndicator()
                    }
                }
            }
            is UiState.Success -> {
                items(
                    items = uiState.users,
                    key = { it.id }
                ) { user ->
                    UserCard(
                        user = user,
                        onClick = { onNavigateToDetail(user) }
                    )
                }
            }
            is UiState.Error -> {
                item {
                    ErrorMessage(
                        message = uiState.message,
                        onRetry = viewModel::loadUsers
                    )
                }
            }
        }
    }
}

@HiltViewModel
class UserViewModel @Inject constructor(
    private val userRepository: UserRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow<UiState>(UiState.Loading)
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    init {
        loadUsers()
    }

    fun loadUsers() {
        viewModelScope.launch {
            userRepository.getUsers()
                .flowOn(Dispatchers.IO)
                .catch { e ->
                    _uiState.value = UiState.Error(e.message ?: "Unknown error")
                }
                .collect { users ->
                    _uiState.value = UiState.Success(users)
                }
        }
    }
}
```

## React Native Development

### Modern React Native with TypeScript

```typescript
import React, { useEffect } from 'react';
import {
  FlatList,
  RefreshControl,
  StyleSheet,
  View,
} from 'react-native';
import { useQuery, useMutation } from '@tanstack/react-query';
import { useNavigation } from '@react-navigation/native';

interface User {
  id: string;
  name: string;
  email: string;
  avatar: string;
}

export const UserListScreen: React.FC = () => {
  const navigation = useNavigation();

  const { data, isLoading, refetch, error } = useQuery<User[]>({
    queryKey: ['users'],
    queryFn: fetchUsers,
  });

  const renderUser = ({ item }: { item: User }) => (
    <UserCard
      user={item}
      onPress={() => navigation.navigate('UserDetail', { userId: item.id })}
    />
  );

  return (
    <View style={styles.container}>
      <FlatList
        data={data}
        renderItem={renderUser}
        keyExtractor={(item) => item.id}
        refreshControl={
          <RefreshControl refreshing={isLoading} onRefresh={refetch} />
        }
        contentContainerStyle={styles.list}
      />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#f5f5f5',
  },
  list: {
    padding: 16,
  },
});
```

### React Native Performance

- **Hermes Engine**: Enable for better performance
- **Reanimated 3**: Smooth 60fps animations
- **FlashList**: Optimized list rendering
- **MMKV**: Fast key-value storage
- **Fast Image**: Optimized image loading

## Flutter Development

### Flutter with Clean Architecture

```dart
import 'package:flutter/material.dart';
import 'package:flutter_bloc/flutter_bloc.dart';
import 'package:get_it/get_it.dart';

class UserListPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return BlocProvider(
      create: (_) => GetIt.I<UserListCubit>()..loadUsers(),
      child: UserListView(),
    );
  }
}

class UserListView extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Users'),
        actions: [
          IconButton(
            icon: Icon(Icons.search),
            onPressed: () => _showSearch(context),
          ),
        ],
      ),
      body: BlocBuilder<UserListCubit, UserListState>(
        builder: (context, state) {
          return switch (state) {
            UserListLoading() => Center(
              child: CircularProgressIndicator(),
            ),
            UserListLoaded(:final users) => RefreshIndicator(
              onRefresh: () => context.read<UserListCubit>().loadUsers(),
              child: ListView.builder(
                itemCount: users.length,
                itemBuilder: (context, index) {
                  final user = users[index];
                  return ListTile(
                    leading: CircleAvatar(
                      backgroundImage: NetworkImage(user.avatar),
                    ),
                    title: Text(user.name),
                    subtitle: Text(user.email),
                    onTap: () => _navigateToDetail(context, user),
                  );
                },
              ),
            ),
            UserListError(:final message) => Center(
              child: Column(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  Text(message),
                  ElevatedButton(
                    onPressed: () => context.read<UserListCubit>().loadUsers(),
                    child: Text('Retry'),
                  ),
                ],
              ),
            ),
          };
        },
      ),
    );
  }
}
```

